// Parse JSON-RPC 2.0 MCP request
const request = msg.payload;
msg.mcp = {
    jsonrpc: request.jsonrpc,
    id: request.id,
    method: request.method,
    params: request.params
};

// Route based on method
if (request.method === 'tools/list') {
    msg.topic = 'mcp/tools/list';
    msg.endpoint = null;
} else if (request.method === 'tools/call') {
    msg.topic = 'mcp/tools/call';
    msg.endpoint = request.params.name;
    msg.payload = request.params.arguments;
} else {
    msg.topic = 'mcp/unknown';
}

return msg;

// Generate MCP tools list response
const tools = [
    {
        name: 'get_soil_data',
        description: 'USDA soil composition by county FIPS',
        inputSchema: {
            type: 'object',
            properties: {
                county_fips: {
                    type: 'string',
                    pattern: '^[0-9]{5}$',
                    description: '5-digit county FIPS code'
                }
            },
            required: ['county_fips']
        }
    },
    {
        name: 'county_lookup',
        description: 'Geographic resolution (name/state → FIPS code)',
        inputSchema: {
            type: 'object',
            properties: {
                term: {
                    type: 'string',
                    description: 'County name or search term'
                },
                state: {
                    type: 'string',
                    description: 'State abbreviation (optional)',
                    pattern: '^[A-Z]{2}$'
                }
            },
            required: ['term']
        }
    },
    {
        name: 'territorial_water_quality',
        description: 'EPA water quality monitoring',
        inputSchema: {
            type: 'object',
            properties: {
                fips: {
                    type: 'string',
                    pattern: '^[0-9]{5}$',
                    description: '5-digit county FIPS code'
                }
            },
            required: ['fips']
        }
    },
    {
        name: 'agricultural_intelligence',
        description: 'AI crop recommendations',
        inputSchema: {
            type: 'object',
            properties: {
                county_fips: {
                    type: 'string',
                    pattern: '^[0-9]{5}$',
                    description: '5-digit county FIPS code'
                },
                crop_type: {
                    type: 'string',
                    description: 'Type of crop (e.g., corn, soybeans, wheat)'
                },
                query: {
                    type: 'string',
                    description: 'Natural language query about the crop'
                }
            },
            required: ['county_fips', 'crop_type', 'query']
        }
    }
];

// Format as JSON-RPC 2.0 response
msg.payload = {
    jsonrpc: '2.0',
    id: msg.mcp.id,
    result: {
        tools: tools
    }
};

return msg;

// Format LeafEngines response as MCP JSON-RPC response
const result = msg.payload;
const content = [];

// Add main result
content.push({
    type: 'text',
    text: JSON.stringify(result, null, 2)
});

// Add cache info if available
if (msg.cache) {
    content.push({
        type: 'text',
        text: `\nCache: ${msg.cache.level} (${msg.cache.age_seconds}s old)`
    });
}

// Add confidence intervals if available
if (msg.confidence) {
    content.push({
        type: 'text',
        text: `\nConfidence intervals: ${JSON.stringify(msg.confidence, null, 2)}`
    });
}

// Format as JSON-RPC 2.0 response
msg.payload = {
    jsonrpc: '2.0',
    id: msg.mcp.id,
    result: {
        content: content
    }
};

return msg;

headers.info:
This flow implements a Model Context Protocol (MCP) server for LeafEngines.

MCP allows AI agents (Claude Desktop, OpenClaw, etc.) to discover and use
LeafEngines tools natively without custom integration code.

Features:
- JSON-RPC 2.0 over HTTP
- Tool discovery via tools/list
- Tool execution via tools/call
- Proper error handling
- Cache and confidence interval reporting

Usage:
1. Configure with your API key
2. Deploy the flow
3. Configure Claude Desktop with:
   {
     "mcpServers": {
       "leafengines": {
         "transport": "streamable-http",
         "url": "http://your-node-red:1880/mcp-server",
         "headers": {
           "x-api-key": "ak_sandbox_your_key_here"
         }
       }
     }
   }

Agents can then use LeafEngines tools directly!
